fn solve(n: i64) -> i64 {
    fn is_palindrome(num: i64) -> bool {
        let s = num.to_string();
        s == s.chars().rev().collect::<String>()
    }

    fn is_valid(num: i64) -> bool {
        let mut count = std::collections::HashMap::new();
        let s = num.to_string();
        for c in s.chars() {
            let k = c.to_digit(10).unwrap() as u8;
            *count.entry(k).or_insert(0) += 1;
        }
        for (k, v) in count {
            if v != k as usize {
                return false;
            }
        }
        true
    }

    let mut i = n + 1;
    while true {
        if is_palindrome(i) && is_valid(i) {
            return i;
        }
        i += 1;
    }
}
